/**
 * LLM 深度分析层
 * - Uses OpenAI when OPENAI_API_KEY is set.
 * - Falls back to DeepSeek when DEEPSEEK_API_KEY is set.
 * - Soft-launch default provider is DeepSeek, because it is cheaper to validate.
 * - 定位: 规则引擎预过滤 → LLM 只对有问题的代码生成修复建议
 * - 所有 AI 修复建议标注 "Generated by AI, verify before applying"
 */

export type LLMScanMode = "standard" | "deep";

interface LLMIssue {
  type: "security" | "quality";
  severity: "critical" | "warning" | "info";
  file: string;
  line: number;
  endLine?: number;
  message: string;
  ruleId: string;
  fixSuggestion: string;
  fixCode?: string;
  codeSnippet?: string;
  referenceUrl?: string;
  aiGenerated?: boolean;
  source?: "llm";
  falsePositive?: boolean;
}

interface LLMAnalysisInput {
  code: string;
  language: string;
  issues: LLMIssue[];
  mode: LLMScanMode;
}

interface LLMAnalysisOutput {
  issues: LLMIssue[];
  modelUsed?: string;
  error?: string;
}

const OPENAI_API_KEY = process.env.OPENAI_API_KEY;
const DEEPSEEK_API_KEY = process.env.DEEPSEEK_API_KEY;
const LLM_TIMEOUT_MS = 15000;
const LLM_MAX_TOKENS: Record<LLMScanMode, number> = {
  standard: 2048,
  deep: 3072,
};

const MODEL_CONFIG = {
  standard: {
    openai: "gpt-4o-mini",
    deepseek: "deepseek-v4-flash",
  },
  deep: {
    openai: "gpt-4o",
    deepseek: "deepseek-v4-pro",
  },
};

export function hasLLMProvider(): boolean {
  return Boolean(OPENAI_API_KEY || DEEPSEEK_API_KEY);
}

function buildPrompt(input: LLMAnalysisInput): string {
  const { code, language, issues, mode } = input;
  const issueSummary = issues
    .map(
      (i, idx) =>
        `${idx + 1}. [${i.severity}] Line ${i.line}: ${i.message.slice(0, 220)} (ruleId: ${i.ruleId})`
    )
    .join("\n");

  const modeDesc = mode === "deep"
    ? "Thorough analysis: enhance each listed static finding with a clear reason and a production-ready fix. Keep the answer concise."
    : "Fast analysis: enhance each listed static finding with a concise, accurate fix suggestion.";

  return `You are a senior code security reviewer. Analyze the following ${language} code and the issues already found by static analysis tools.

${modeDesc}

CODE:
\`\`\`${language}
${code.slice(0, 8000)}
\`\`\`

ISSUES FOUND BY STATIC ANALYSIS:
${issueSummary}

For each listed static issue, provide:
1. line number
2. the original ruleId exactly as provided
3. a clear explanation of why it's a problem
4. a concise fix suggestion
5. mark as "ai_enhanced"

Output strictly as JSON array:
[
  {
    "line": 42,
    "ruleId": "original-rule-id",
    "severity": "critical|warning|info",
    "message": "Clear explanation",
    "fixSuggestion": "Short fix, max 180 chars",
    "fixCode": "optional short snippet",
    "aiEnhanced": true,
    "falsePositive": false
  }
]

Rules:
- ONLY output the JSON array, no markdown, no explanations outside JSON
- Return one JSON object for each listed static issue whenever possible
- Do NOT invent issues that are not in the static analysis list
- Do NOT hallucinate APIs or functions that don't exist
- If unsure about a fix, keep the original finding and write a cautious fixSuggestion
- Keep each object compact
- Keep fixCode short; omit fixCode if a compact syntactically valid snippet is not possible
`;
}

async function callOpenAI(
  prompt: string,
  mode: LLMScanMode
): Promise<{ content: string; model: string } | null> {
  if (!OPENAI_API_KEY) return null;

  const model = MODEL_CONFIG[mode].openai;
  const res = await fetch("https://api.openai.com/v1/chat/completions", {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      Authorization: `Bearer ${OPENAI_API_KEY}`,
    },
    body: JSON.stringify({
      model,
      messages: [
        { role: "system", content: "You are a precise code security reviewer. Output only valid JSON." },
        { role: "user", content: prompt },
      ],
      temperature: 0.2,
      max_tokens: LLM_MAX_TOKENS[mode],
    }),
    signal: AbortSignal.timeout(LLM_TIMEOUT_MS),
  });

  if (!res.ok) {
    const text = await res.text().catch(() => "Unknown error");
    throw new Error(`OpenAI API ${res.status}: ${text.slice(0, 200)}`);
  }

  const data = await res.json();
  const content = data.choices?.[0]?.message?.content;
  if (!content) throw new Error("OpenAI returned empty content");

  return { content, model };
}

async function callDeepSeek(
  prompt: string,
  mode: LLMScanMode
): Promise<{ content: string; model: string } | null> {
  if (!DEEPSEEK_API_KEY) return null;

  const model = MODEL_CONFIG[mode].deepseek;
  const res = await fetch("https://api.deepseek.com/v1/chat/completions", {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      Authorization: `Bearer ${DEEPSEEK_API_KEY}`,
    },
    body: JSON.stringify({
      model,
      messages: [
        { role: "system", content: "You are a precise code security reviewer. Output only valid JSON." },
        { role: "user", content: prompt },
      ],
      thinking: { type: "disabled" },
      temperature: 0.2,
      max_tokens: LLM_MAX_TOKENS[mode],
    }),
    signal: AbortSignal.timeout(LLM_TIMEOUT_MS),
  });

  if (!res.ok) {
    const text = await res.text().catch(() => "Unknown error");
    throw new Error(`DeepSeek API ${res.status}: ${text.slice(0, 200)}`);
  }

  const data = await res.json();
  const content = data.choices?.[0]?.message?.content;
  if (!content) throw new Error("DeepSeek returned empty content");

  return { content, model };
}

function parseIssuesArray(value: unknown): LLMIssue[] {
  if (!Array.isArray(value)) {
    throw new Error("LLM response is not an array");
  }
  return value;
}

function sanitizeJsonLike(value: string): string {
  return value
    .replace(/```(?:json)?/gi, "")
    .replace(/```/g, "")
    .replace(/,\s*([\]}])/g, "$1")
    .trim();
}

function extractCompleteJsonObjects(arrayText: string): LLMIssue[] {
  const objects: LLMIssue[] = [];
  let start = -1;
  let depth = 0;
  let inString = false;
  let escaped = false;

  for (let i = 0; i < arrayText.length; i++) {
    const char = arrayText[i];

    if (inString) {
      if (escaped) escaped = false;
      else if (char === "\\") escaped = true;
      else if (char === "\"") inString = false;
      continue;
    }

    if (char === "\"") {
      inString = true;
      continue;
    }

    if (char === "{") {
      if (depth === 0) start = i;
      depth++;
      continue;
    }

    if (char === "}") {
      depth--;
      if (depth === 0 && start >= 0) {
        const objectText = sanitizeJsonLike(arrayText.slice(start, i + 1));
        try {
          objects.push(JSON.parse(objectText));
        } catch {
          // Keep looking for later complete objects.
        }
        start = -1;
      }
    }
  }

  if (!objects.length) {
    throw new Error("No complete JSON objects found in LLM response");
  }
  return objects;
}

function parseLLMResponse(raw: string): LLMIssue[] {
  // 尝试提取 JSON 数组（LLM 可能包裹在 markdown code block 中）
  const cleanedRaw = sanitizeJsonLike(raw);
  const arrayStart = cleanedRaw.indexOf("[");
  if (arrayStart < 0) {
    throw new Error("No JSON array start found in LLM response");
  }

  const arrayEnd = cleanedRaw.lastIndexOf("]");
  const arrayText = arrayEnd > arrayStart
    ? cleanedRaw.slice(arrayStart, arrayEnd + 1)
    : cleanedRaw.slice(arrayStart);

  try {
    return parseIssuesArray(JSON.parse(arrayText));
  } catch {
    // 尝试清理常见 LLM 格式问题后重新解析
    try {
      return parseIssuesArray(JSON.parse(sanitizeJsonLike(arrayText).replace(/\n/g, " ")));
    } catch {
      // If the model was truncated after several full objects, keep the usable objects.
      return extractCompleteJsonObjects(arrayText);
    }
  }
}

export async function runLLMAnalysis(
  input: LLMAnalysisInput
): Promise<LLMAnalysisOutput> {
  const prompt = buildPrompt(input);

  // 1. 尝试 OpenAI
  let result: { content: string; model: string } | null = null;
  let modelUsed = "unknown";

  try {
    result = await callOpenAI(prompt, input.mode);
    if (result) modelUsed = result.model;
  } catch (openaiErr) {
    console.error("OpenAI failed, trying DeepSeek fallback:", openaiErr);
  }

  // 2. OpenAI 失败 → 自动切换 DeepSeek
  if (!result) {
    try {
      result = await callDeepSeek(prompt, input.mode);
      if (result) modelUsed = result.model;
    } catch (deepseekErr) {
      console.error("DeepSeek fallback also failed:", deepseekErr);
      const detail = deepseekErr instanceof Error ? deepseekErr.message : String(deepseekErr);
      return {
        issues: [],
        error: `AI analysis temporarily unavailable. Showing rule-engine results only. ${detail.slice(0, 160)}`,
      };
    }
  }

  if (!result) {
    return {
      issues: [],
      error: "AI analysis temporarily unavailable. Showing rule-engine results only.",
    };
  }

  // 3. 解析 LLM 输出
  let parsed: LLMIssue[];
  try {
    parsed = parseLLMResponse(result.content);
  } catch (parseErr) {
    console.error("Failed to parse LLM response:", parseErr, "Raw:", result.content.slice(0, 500));
    return {
      issues: [],
      error: "AI analysis response malformed. Showing rule-engine results only.",
    };
  }

  // 4. 转换为内部 Issue 格式
  const llmIssues: LLMIssue[] = parsed
    .filter((item) => !item.falsePositive) // 过滤掉 LLM 认为是误报的项目
    .map((item) => ({
      type: "security" as const,
      severity: item.severity || "warning",
      file: "input",
      line: item.line || 0,
      endLine: item.line || 0,
      message: item.message || "AI-generated suggestion",
      ruleId: item.ruleId || `llm-${input.mode}-${modelUsed}`,
      fixSuggestion: `${item.fixSuggestion || ""}\n\nGenerated by AI, verify before applying.`,
      fixCode: item.fixCode || undefined,
      codeSnippet: undefined,
      referenceUrl: undefined,
      aiGenerated: true,
      source: "llm" as const,
    }));

  return { issues: llmIssues, modelUsed };
}
